def _store_example(contribution_id: str, label: str, img_bytes: bytes) -> Dict[str, Any]:
    label = _normalize_label(label)
    if not label:
        raise ValueError("Empty label")

    im = _decode_image_bytes(img_bytes)
    image_sha = _sha256_bytes(img_bytes)
    rel_dir = os.path.join("images", label)
    filename = f"{image_sha}.jpg"
    rel_path = os.path.join(rel_dir, filename)
    abs_path = os.path.join(DATASET_DIR, rel_path)

    if not os.path.exists(abs_path):
        w, h = _save_image(im, abs_path)
    else:
        w, h = im.size[0], im.size[1]

    ex_id = str(uuid.uuid4())
    conn = _get_conn()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO examples (id, created_at, contribution_id, label, image_relpath, image_sha256, width, height)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (ex_id, _utc_now_iso(), contribution_id, label, rel_path.replace("\\", "/"), image_sha, w, h),
    )
    conn.commit()
    conn.close()
    return {"example_id": ex_id, "label": label, "image_relpath": rel_path.replace("\\", "/"), "image_sha256": image_sha}


def _insert_contribution(kind: str, contributor_id: Optional[str], source_filename: Optional[str], content_sha256: str) -> str:
    cid = str(uuid.uuid4())
