@app.post("/upload/csv")
async def upload_csv(
    file: UploadFile = File(...),
    contributor_id: Optional[str] = Form(None),
    background_tasks: BackgroundTasks = None,
):
    if not file.filename.lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="Only CSV files are supported")

    csv_bytes = _validate_upload_size(file)
    sha = _sha256_bytes(csv_bytes)
    contribution_id = _insert_contribution(kind="csv", contributor_id=contributor_id, source_filename=file.filename, content_sha256=sha)

    upload_path = os.path.join(UPLOAD_DIR, f"{contribution_id}.csv")
    with open(upload_path, "wb") as f:
        f.write(csv_bytes)

    df = _read_csv_bytes(csv_bytes)
    cols = {c.lower(): c for c in df.columns}
    if "label" not in cols:
        _update_contribution(contribution_id, status="error", error="CSV must contain 'label' column")
        raise HTTPException(status_code=400, detail="CSV must contain 'label' column")

    has_image_b64 = "image_b64" in cols
    has_image_path = "image_path" in cols
    if not (has_image_b64 or has_image_path):
        _update_contribution(contribution_id, status="error", error="CSV must contain 'image_b64' or 'image_path' column")
        raise HTTPException(status_code=400, detail="CSV must contain 'image_b64' or 'image_path' column")

    num_rows = int(len(df))
    num_images = 0
    errors = 0

    import base64

    _update_contribution(contribution_id, status="processing", num_rows=num_rows, num_images=0, error=None)

    for i, row in df.iterrows():
        try:
            label = row[cols["label"]]
            if has_image_b64 and pd.notna(row[cols["image_b64"]]):
                b64 = str(row[cols["image_b64"]]).strip()
                if "," in b64 and b64.lower().startswith("data:"):
                    b64 = b64.split(",", 1)[1]
                img_bytes = base64.b64decode(b64, validate=False)
            else:
                p = str(row[cols["image_path"]]).strip()
                if not p:
                    raise ValueError("Empty image_path")
                if p.startswith("http://") or p.startswith("https://"):
                    raise ValueError("Remote URLs not allowed in image_path")
                if os.path.isabs(p):
                    raise ValueError("Absolute paths not allowed in image_path")
                base_dir = os.path.dirname(upload_path)
                abs_p = os.path.normpath(os.path.join(base_dir, p))
                if not abs_p.startswith(os.path.abspath(base_dir)):
                    raise ValueError("Path traversal detected")
                with open(abs_p, "rb") as f:
                    img_bytes = f.read()

            _store_example(contribution_id, label, img_bytes)
            num_images += 1
        except Exception:
            errors += 1

    if num_images == 0:
        _update_contribution(contribution_id, status="error", error="No valid images found in CSV", num_images=0)
        raise HTTPException(status_code=400, detail="No valid images found in CSV")

    status = "completed" if errors == 0 else "completed_with_errors"
    _update_contribution(contribution_id, status=status, error=(None if errors == 0 else f"{errors} rows failed"), num_images=num_images)

    return {"contribution_id": contribution_id, "num_rows": num_rows, "num_images_added": num_images, "rows_failed": errors}


@app.post("/upload/zip")
async def upload_zip(
    file: UploadFile = File(...),
    contributor_id: Optional[str] = Form(None),
):
    if not file.filename.lower().endswith(".zip"):
        raise HTTPException(status_code=400, detail="Only ZIP files are supported")

    zip_bytes = _validate_upload_size(file)
    sha = _sha256_bytes(zip_bytes)
    contribution_id = _insert_contribution(kind="zip", contributor_id=contributor_id, source_filename=file.filename, content_sha256=sha)

    upload_path = os.path.join(UPLOAD_DIR, f"{contribution_id}.zip")
    with open(upload_path, "wb") as f:
        f.write(zip_bytes)

    extract_dir = os.path.join(UPLOAD_DIR, f"{contribution_id}_unzipped")
    if os.path.exists(extract_dir):
        shutil.rmtree(extract_dir, ignore_errors=True)
    _safe_mkdir(extract_dir)

    num_images = 0
    errors = 0
    _update_contribution(contribution_id, status="processing", num_rows=None, num_images=0, error=None)

    try:
        with zipfile.ZipFile(io.BytesIO(zip_bytes), "r") as z:
            for info in z.infolist():
                name = info.filename
                if name.endswith("/") or name.startswith("__MACOSX/"):
                    continue
                norm = os.path.normpath(name).replace("\\", "/")
                if norm.startswith("../") or norm.startswith("..\\") or norm.startswith("/"):
                    errors += 1
                    continue
                parts = [p for p in norm.split("/") if p]
                if len(parts) < 2:
                    continue
                label = parts[0]
                ext = os.path.splitext(parts[-1])[1].lower()
                if ext not in [".jpg", ".jpeg", ".png", ".webp"]:
                    continue
                try:
                    img_bytes = z.read(info)
                    if ext in [".png", ".webp"]:
                        im = Image.open(io.BytesIO(img_bytes)).convert("RGB")
                        buf = io.BytesIO()
                        im.save(buf, format="JPEG", quality=92, optimize=True)
                        img_bytes = buf.getvalue()
                    _store_example(contribution_id, label, img_bytes)
                    num_images += 1
                except Exception:
                    errors += 1
    except Exception as e:
        _update_contribution(contribution_id, status="error", error=f"Invalid ZIP: {e}", num_images=num_images)
        raise HTTPException(status_code=400, detail=f"Invalid ZIP: {e}")
    finally:
        try:
            shutil.rmtree(extract_dir, ignore_errors=True)
        except Exception:
            pass

    if num_images == 0:
        _update_contribution(contribution_id, status="error", error="No valid images found in ZIP", num_images=0)
        raise HTTPException(status_code=400, detail="No valid images found in ZIP")

    status = "completed" if errors == 0 else "completed_with_errors"
    _update_contribution(contribution_id, status=status, error=(None if errors == 0 else f"{errors} files failed"), num_images=num_images)

    return {"contribution_id": contribution_id, "num_images_added": num_images, "files_failed": errors}


@app.post("/upload/example")
async def upload_example(
    image: UploadFile = File(...),
    label: str = Form(...),
    contributor_id: Optional[str] = Form(None),
):
    img_bytes = _validate_upload_size(image)
    sha = _sha256_bytes(img_bytes)
    contribution_id = _insert_contribution(kind="single", contributor_id=contributor_id, source_filename=image.filename, content_sha256=sha)
    _update_contribution(contribution_id, status="processing", num_rows=1, num_images=0, error=None)
    try:
        ex = _store_example(contribution_id, label, img_bytes)
        _update_contribution(contribution_id, status="completed", num_rows=1, num_images=1, error=None)
        return {"contribution_id": contribution_id, **ex}
    except Exception as e:
        _update_contribution(contribution_id, status="error", error=str(e), num_rows=1, num_images=0)
        raise HTTPException(status_code=400, detail=str(e))


@app.post("/train")
def train(req: TrainRequest, background_tasks: BackgroundTasks):
    global TRAIN_THREAD

    st = _get_status()
    if st.get("state") == "running":
        raise HTTPException(status_code=409, detail="Training already running")

    image_size = int(req.image_size or DEFAULT_IMAGE_SIZE)
    batch_size = int(req.batch_size or DEFAULT_BATCH_SIZE)
    epochs = int(req.epochs or DEFAULT_EPOCHS)
    lr = float(req.learning_rate or DEFAULT_LEARNING_RATE)
    val_split = float(req.val_split if req.val_split is not None else DEFAULT_VAL_SPLIT)
    test_split = float(req.test_split if req.test_split is not None else DEFAULT_TEST_SPLIT)

    if image_size < 32 or image_size > 1024:
        raise HTTPException(status_code=400, detail="image_size out of range")
    if batch_size < 1 or batch_size > 512:
        raise HTTPException(status_code=400, detail="batch_size out of range")
    if epochs < 1 or epochs > 200:
        raise HTTPException(status_code=400, detail="epochs out of range")
    if lr <= 0 or lr > 1:
        raise HTTPException(status_code=400, detail="learning_rate out of range")
    if not (0.0 <= val_split < 1.0) or not (0.0 <= test_split < 1.0) or (val_split + test_split) >= 1.0:
        raise HTTPException(status_code=400, detail="Invalid splits")

    job_id = str(uuid.uuid4())
    _set_status(state="queued", job_id=job_id, started_at=_utc_now_iso(), ended_at=None, message="Queued", progress=0.0)

    TRAIN_THREAD = threading.Thread(
        target=_train_job,
        args=(job_id, image_size, batch_size, epochs, lr, val_split, test_split),
        daemon=True,
    )
    TRAIN_THREAD.start()

    return {"job_id": job_id, "status_url": "/status"}


class PredictResponse(BaseModel):
    label: str
    confidence: float
    top_k: List[Dict[str, Any]]
    model_version: int


def _load_latest_model() -> Tuple[keras.Model, Dict[str, Any]]:
    info = _latest_model_info()
    if not info:
        raise HTTPException(status_code=404, detail="No trained model available")
    model_path = os.path.join(info["model_dir"], "saved_model")
    try:
        model = keras.models.load_model(model_path)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to load model: {e}")
    return model, info


@app.post("/predict", response_model=PredictResponse)
async def predict(image: UploadFile = File(...), top_k: int = Form(5)):
    img_bytes = _validate_upload_size(image)
    model, info = _load_latest_model()
    labels = info["labels"]
    image_size = int(info["image_size"])

    try:
        im = _decode_image_bytes(img_bytes)
        im = im.resize((image_size, image_size))
        arr = np.asarray(im).astype(np.float32)
        x = np.expand_dims(arr, axis=0)
        probs = model.predict(x, verbose=0)[0]
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid image: {e}")

    k = int(max(1, min(top_k, len(labels))))
    idx = np.argsort(-probs)[:k]
    top = [{"label": labels[int(i)], "confidence": float(probs[int(i)])} for i in idx]
    best = top[0]
    return PredictResponse(label=best["label"], confidence=best["confidence"], top_k=top, model_version=int(info["version"]))


@app.get("/export/dataset")
def export_dataset():
    export_name = f"dataset_export_{int(time.time())}.zip"
    export_path = os.path.join(EXPORT_DIR, export_name)

    rows = _get_all_examples()
    if not rows:
        raise HTTPException(status_code=404, detail="No examples available")

    with zipfile.ZipFile(export_path, "w", compression=zipfile.ZIP_DEFLATED) as z:
        conn = _get_conn()
        cur = conn.cursor()
        cur.execute("SELECT id, created_at, contribution_id, label, image_relpath, image_sha256, width, height FROM examples")
        ex_rows = cur.fetchall()
        conn.close()

        manifest = []
        for r in ex_rows:
            rel = r["image_relpath"].replace("\\", "/")
            abs_p = os.path.join(DATASET_DIR, rel)
            if os.path.exists(abs_p):
                z.write(abs_p, arcname=rel)
            manifest.append({k: r[k] for k in r.keys()})

        z.writestr("manifest.json", json.dumps(manifest, ensure_ascii=False, indent=2))

    return {"export_zip": export_name, "path": export_path}


